/* Tree fastpath:
 *   safe leaf  -> returns fraud count in [0..5]
 *   unsafe leaf -> returns 0xFF (caller falls back to KNN)
 */
uint8_t tree_predict_safe_c(const int16_t* q) {
    int32_t node = 0;
    for (;;) {
        const tree_node_t* n = &TREE_NODES[node];
        int32_t left = n->left;
        if (left < 0) {
            uint32_t leaf = (uint32_t)(-1 - left);
            if (TREE_LEAF_SAFE[leaf]) return TREE_LEAF_COUNT_OF[leaf];
            return 0xFFu;
        }
        node = (q[n->feature] <= n->threshold) ? left : n->right;
    }
}

